-- Create "directory_departments" table
CREATE TABLE "directory_departments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "provider" character varying NOT NULL,
  "external_id" character varying NOT NULL,
  "parent_external_id" character varying NULL,
  "name" character varying NOT NULL,
  "display_name" character varying NOT NULL,
  "path" character varying NOT NULL,
  "parent_path" character varying NULL,
  "level" bigint NOT NULL DEFAULT 0,
  "source" character varying NULL,
  "member_count" bigint NOT NULL DEFAULT 0,
  "source_updated_at" timestamptz NULL,
  "synced_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "directorydepartment_path" to table: "directory_departments"
CREATE INDEX "directorydepartment_path" ON "directory_departments" ("path");
-- Create index "directorydepartment_provider_external_id" to table: "directory_departments"
CREATE UNIQUE INDEX "directorydepartment_provider_external_id" ON "directory_departments" ("provider", "external_id");
-- Create index "directorydepartment_provider_path" to table: "directory_departments"
CREATE INDEX "directorydepartment_provider_path" ON "directory_departments" ("provider", "path");
-- Create "directory_sync_runs" table
CREATE TABLE "directory_sync_runs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "provider" character varying NOT NULL,
  "page_size" bigint NOT NULL,
  "updated_after" timestamptz NULL,
  "status" character varying NOT NULL DEFAULT 'succeeded',
  "failure_code" character varying NOT NULL DEFAULT '',
  "failure_message" character varying NOT NULL DEFAULT '',
  "department_pages" bigint NOT NULL,
  "user_pages" bigint NOT NULL,
  "departments_upserted" bigint NOT NULL,
  "users_upserted" bigint NOT NULL,
  "synced_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "directorysyncrun_provider_status_synced_at" to table: "directory_sync_runs"
CREATE INDEX "directorysyncrun_provider_status_synced_at" ON "directory_sync_runs" ("provider", "status", "synced_at");
-- Create index "directorysyncrun_provider_synced_at" to table: "directory_sync_runs"
CREATE INDEX "directorysyncrun_provider_synced_at" ON "directory_sync_runs" ("provider", "synced_at");
-- Create index "directorysyncrun_synced_at" to table: "directory_sync_runs"
CREATE INDEX "directorysyncrun_synced_at" ON "directory_sync_runs" ("synced_at");
-- Create "directory_users" table
CREATE TABLE "directory_users" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "provider" character varying NOT NULL,
  "subject" character varying NOT NULL,
  "external_id" character varying NOT NULL,
  "username" character varying NOT NULL,
  "display_name" character varying NOT NULL,
  "email" character varying NULL,
  "job_title" character varying NULL,
  "department" character varying NULL,
  "section" character varying NULL,
  "department_path" character varying NULL,
  "department_paths" jsonb NOT NULL,
  "department_external_ids" jsonb NOT NULL,
  "active" boolean NOT NULL DEFAULT true,
  "source_updated_at" timestamptz NULL,
  "synced_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "directoryuser_display_name" to table: "directory_users"
CREATE INDEX "directoryuser_display_name" ON "directory_users" ("display_name");
-- Create index "directoryuser_provider_active" to table: "directory_users"
CREATE INDEX "directoryuser_provider_active" ON "directory_users" ("provider", "active");
-- Create index "directoryuser_provider_external_id" to table: "directory_users"
CREATE UNIQUE INDEX "directoryuser_provider_external_id" ON "directory_users" ("provider", "external_id");
-- Create index "directoryuser_provider_subject" to table: "directory_users"
CREATE UNIQUE INDEX "directoryuser_provider_subject" ON "directory_users" ("provider", "subject");
-- Create "rbac_assignments" table
CREATE TABLE "rbac_assignments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "subject_kind" character varying NOT NULL,
  "subject_key" character varying NOT NULL,
  "role" character varying NOT NULL,
  "scope_kind" character varying NOT NULL,
  "scope_key" character varying NOT NULL DEFAULT '',
  "enabled" boolean NOT NULL DEFAULT true,
  "created_by" character varying NOT NULL,
  "updated_by" character varying NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "rbacassignment_scope_kind_scope_key_enabled" to table: "rbac_assignments"
CREATE INDEX "rbacassignment_scope_kind_scope_key_enabled" ON "rbac_assignments" ("scope_kind", "scope_key", "enabled");
-- Create index "rbacassignment_subject_kind_subject_key_enabled" to table: "rbac_assignments"
CREATE INDEX "rbacassignment_subject_kind_subject_key_enabled" ON "rbac_assignments" ("subject_kind", "subject_key", "enabled");
-- Create index "rbacassignment_subject_kind_subject_key_role_scope_kind_scope_k" to table: "rbac_assignments"
CREATE UNIQUE INDEX "rbacassignment_subject_kind_subject_key_role_scope_kind_scope_k" ON "rbac_assignments" ("subject_kind", "subject_key", "role", "scope_kind", "scope_key");
